// Only the important change shown — rest of your Register code stays identical

import { loadSlim } from "tsparticles-slim";

const particlesInit = useCallback(async(engine)=>{
  await loadSlim(engine);
},[]);

const [particlesReady,setParticlesReady] = useState(false);

useEffect(()=>{
  nameRef.current?.focus();
  setParticlesReady(true);
},[]);

{particlesReady && (
  <Particles
    id="tsparticles"
    init={particlesInit}
    className="absolute inset-0"
    options={{
      fpsLimit:60,
      particles:{
        number:{value:30},
        size:{value:2},
        move:{speed:0.3},
        opacity:{value:0.3},
        links:{
          enable:true,
          distance:140,
          color:"#ffffff",
          opacity:0.1
        }
      }
    }}
  />
)}
